import React, { useState, useEffect } from 'react';
import img1 from './images/download.webp';
import img2 from './images/images.jpeg';
import img3 from './images/photo-1437482078695-73f5ca6c96e2.avif';
import './Home.css';

const Home = () => {
  const [currentSlide, setCurrentSlide] = useState(0);

  const images = [
    {
      src: img1,
      title: "Welcome to Sri Lanka Online Aquarium",
      description: "Discover beautiful aquatic life from Sri Lanka"
    },
    {
      src: img2,
      title: "Fish Tank With Furniture",
      description: "Stylish fish tanks perfectly matched with furniture"
    },
    {
      src: img3,
      title: "Fish Pond & Tank Maintenance",
      description: "Professional care for ponds and aquarium tanks"
    }
  ];

  // Auto slide
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % images.length);
    }, 3000);
    return () => clearInterval(timer);
  }, [images.length]);

  return (
    <div className="home-page">

      <div className="carousel-custom">

        {/* Slide */}
        <div className="carousel-card">
          <img
            src={images[currentSlide].src}
            alt={images[currentSlide].title}
            className="carousel-img"
          />

          {/* TEXT UNDER IMAGE */}
          <div className="carousel-text-below">
            <h2>{images[currentSlide].title}</h2>
            <p>{images[currentSlide].description}</p>
          </div>
        </div>

        {/* Controls */}
        <button className="carousel-btn prev" onClick={() =>
          setCurrentSlide((currentSlide - 1 + images.length) % images.length)
        }>
          ❮
        </button>

        <button className="carousel-btn next" onClick={() =>
          setCurrentSlide((currentSlide + 1) % images.length)
        }>
          ❯
        </button>

      </div>
    </div>
  );
};

export default Home;
